fn dom_css_dim(d: Dimension) -> String {
    match d.unit {
        DimensionUnit::Px => format!("{}px", d.value),
        DimensionUnit::Percent => format!("{}%", d.value),
        DimensionUnit::Auto => "auto".into(),
        DimensionUnit::Fr => format!("{}fr", d.value),
    }
}

fn dom_css_hex(c: Color) -> String {
    let arr = c.to_array_f32();
    format!(
        "#{:02x}{:02x}{:02x}",
        (arr[0] * 255.0).round() as u8,
        (arr[1] * 255.0).round() as u8,
        (arr[2] * 255.0).round() as u8,
    )
}

